{"content":"package ru.samtakoy.stocks.feature.settings

import com.arkivanov.mvikotlin.core.store.Reducer
import com.arkivanov.mvikotlin.core.store.Store
import com.arkivanov.mvikotlin.core.store.StoreFactory
import com.arkivanov.mvikotlin.extensions.coroutines.CoroutineBootstrapper
import com.arkivanov.mvikotlin.extensions.coroutines.CoroutineExecutor
import kotlinx.coroutines.launch
import ru.samtakoy.stocks.core.theme.domain.ThemeMode
import ru.samtakoy.stocks.core.theme.domain.ThemeRepository

internal class SettingsStoreFactory(
    private val storeFactory: StoreFactory,
    private val themeRepository: ThemeRepository,
) {
    fun create(): SettingsStore =
        object : SettingsStore, Store<SettingsStore.Intent, SettingsStore.State, Nothing>
        by storeFactory.create(
            name = "SettingsStore",
            initialState = SettingsStore.State(),
            bootstrapper = Bootstrapper(),
            executorFactory = ::Executor,
            reducer = SettingsReducer,
        ) {}

    private sealed interface Action { data class ThemeLoaded(val mode: ThemeMode) : Action }
    private sealed interface Msg { data class ThemeChanged(val mode: ThemeMode) : Msg }

    private inner class Bootstrapper : CoroutineBootstrapper<Action>() {
        override fun invoke() {
            scope.launch { dispatch(Action.ThemeLoaded(themeRepository.getTheme())) }
        }
    }

    private inner class Executor : CoroutineExecutor<SettingsStore.Intent, Action, SettingsStore.State, Msg, Nothing>() {
        override fun executeAction(action: Action) { when (action) { is Action.ThemeLoaded -> dispatch(Msg.ThemeChanged(action.mode)) } }
        override fun executeIntent(intent: SettingsStore.Intent) {
            when (intent) { is SettingsStore.Intent.SetTheme -> scope.launch { themeRepository.setTheme(intent.mode); dispatch(Msg.ThemeChanged(intent.mode)) } }
        }
    }

